给你搭了一个**浅色模式的时空实验室**——把原来的深空黑换成了干净的素白与冰川蓝调，公式和网格都重新适配了亮色环境，阅读起来更清爽：

<div id="response-root" style="width: 100%; max-width: 800px; margin: 10px auto; font-family: 'Inter', system-ui, -apple-system, sans-serif; background: #ffffff; border-radius: 16px; overflow: hidden; border: 1px solid #e5e7eb; position: relative; box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.04), 0 4px 6px -2px rgba(0, 0, 0, 0.02);">

    <!-- 状态栏 -->
    <div id="status-bar-light" style="position: absolute; top: 12px; left: 12px; z-index: 100; font-size: 10px; font-family: 'SF Mono', monospace; color: #6b7280; background: rgba(255,255,255,0.85); backdrop-filter: blur(4px); padding: 4px 10px; border-radius: 6px; border: 1px solid #e5e7eb;">
        [ SYSTEM: INITIALIZING VIRTUAL LABORATORY ]
    </div>

    <!-- 仿真容器 -->
    <div id="sim-container-light" style="width: 100%; height: 500px; background: linear-gradient(180deg, #ffffff 0%, #f3f4f6 100%);"></div>

    <!-- 物理说明 -->
    <div style="padding: 18px 24px; background: #ffffff; border-top: 1px solid #e5e7eb;">
        <div style="display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 8px;">
            <div style="color: #1e3a8a; font-size: 15px; font-weight: 700; letter-spacing: 0.3px; font-family: system-ui;">
                重力场与空间曲率 <span style="font-weight:400; color:#64748b; font-size:13px;">(Spacetime Curvature)</span>
            </div>
            <div style="color: #94a3b8; font-size: 11px; font-family: 'SF Mono', monospace; background: #f1f5f9; padding: 3px 10px; border-radius: 4px; border: 1px solid #e2e8f0;">
                Gμν + Λgμν = 8πG/c⁴ Tμν
            </div>
        </div>
        <p style="color: #475569; font-size: 13px; margin: 10px 0 0 0; line-height: 1.6;">
            正在模拟大质量天体对周围时空网格的挤压。白色背景下，形变网格以靛蓝线条呈现，曲率阱的深浅对比更加清晰，直观展示广义相对论的引力几何本质。
        </p>
    </div>

    <script>
        (function() {
            const containerId = 'sim-container-light';
            const statusId = 'status-bar-light';

            if (typeof THREE === 'undefined') {
                const script = document.createElement('script');
                script.src = 'https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js';
                script.onload = () => initSim();
                script.onerror = () => {
                    const el = document.getElementById(statusId);
                    if(el) el.innerHTML = '<span style="color:#dc2626">[ ERROR: FAILED TO LOAD PHYSICS ENGINE ]</span>';
                };
                document.head.appendChild(script);
            } else {
                initSim();
            }

            function initSim() {
                const container = document.getElementById(containerId);
                const status = document.getElementById(statusId);
                if (!container) return;

                if(status) status.innerHTML = '<span style="color:#059669">● PHYSICS_CORE_ACTIVE</span>';

                const scene = new THREE.Scene();
                scene.background = new THREE.Color(0xf3f4f6);

                const camera = new THREE.PerspectiveCamera(60, container.clientWidth / container.clientHeight, 0.1, 1000);
                camera.position.set(10, 8, 10);
                camera.lookAt(0, 0, 0);

                const renderer = new THREE.WebGLRenderer({ antialias: true });
                renderer.setSize(container.clientWidth, container.clientHeight);
                renderer.setPixelRatio(window.devicePixelRatio);
                renderer.setClearColor(0xf3f4f6, 1);
                container.appendChild(renderer.domElement);

                // 时空网格：靛蓝 wireframe，适配白色背景
                const size = 20;
                const divisions = 40;
                const geometry = new THREE.PlaneGeometry(size, size, divisions, divisions);
                const material = new THREE.MeshBasicMaterial({ 
                    color: 0x1e3a8a, 
                    wireframe: true, 
                    transparent: true, 
                    opacity: 0.10 
                });

                const grid = new THREE.Mesh(geometry, material);
                grid.rotation.x = -Math.PI / 2;
                scene.add(grid);

                // 大质量核心：深 Slate 色，保证在浅色背景上的对比度
                const coreGeo = new THREE.SphereGeometry(0.5, 32, 32);
                const coreMat = new THREE.MeshBasicMaterial({ color: 0x0f172a });
                const core = new THREE.Mesh(coreGeo, coreMat);
                scene.add(core);

                // 柔和光源系统
                const light = new THREE.PointLight(0x3b82f6, 1.5, 10);
                scene.add(light);

                const ambientLight = new THREE.AmbientLight(0xffffff, 0.7);
                scene.add(ambientLight);

                // 保存原始顶点以计算相对偏移
                const originalPositions = geometry.attributes.position.array.slice();

                let time = 0;
                function animate() {
                    requestAnimationFrame(animate);
                    time += 0.02;

                    // 天体圆周运动
                    const radius = 4;
                    const centerX = Math.cos(time) * radius;
                    const centerZ = Math.sin(time) * radius;
                    core.position.set(centerX, 0, centerZ);
                    light.position.set(centerX, 1, centerZ);

                    // 实时扭曲网格：制造引力阱
                    const pos = geometry.attributes.position.array;
                    for (let i = 0; i < pos.length; i += 3) {
                        const x = pos[i];
                        const dx = x - centerX;
                        // PlaneGeometry 旋转后，原 y 轴映射到世界 -z
                        const dz = (-originalPositions[i+1]) - centerZ;
                        const dist = Math.sqrt(dx * dx + dz * dz);

                        const depth = 2.5;
                        const spread = 2.0;
                        const deformation = depth / (1 + Math.pow(dist / spread, 2));

                        pos[i + 2] = deformation; // 本地 z 控制世界 y 的下沉
                    }
                    geometry.attributes.position.needsUpdate = true;

                    // 自动环绕相机
                    const camRadius = 15;
                    camera.position.x = Math.sin(time * 0.2) * camRadius;
                    camera.position.z = Math.cos(time * 0.2) * camRadius;
                    camera.lookAt(0, -1, 0);

                    renderer.render(scene, camera);
                }

                animate();

                // 响应式
                const onResize = () => {
                    if (!container) return;
                    camera.aspect = container.clientWidth / container.clientHeight;
                    camera.updateProjectionMatrix();
                    renderer.setSize(container.clientWidth, container.clientHeight);
                };
                window.addEventListener('resize', onResize);
            }
        })();
    </script>
</div>

